export const _POST =
  (implementation: PostCheckoutSessions) =>
  async (
    request: NextRequest,
    { params }: { params: unknown },
  ): Promise<Response> => {
    const input = {
      params: undefined,
      // TODO: this swallows repeated parameters
      query: undefined,
      body: parseRequestInput(
        postCheckoutSessionsBodySchema,
        await request.json(),
        RequestInputType.RequestBody,
      ),
    }

    const responder = {
      with200() {
        return new KoaRuntimeResponse<t_checkout_session>(200)
      },
      withDefault(status: StatusCode) {
        return new KoaRuntimeResponse<t_error>(status)
      },
      withStatus(status: StatusCode) {
        return new KoaRuntimeResponse(status)
      },
    }

    const { status, body } = await implementation(input, responder, { request })
      .then((it) => it.unpack())
      .catch((err) => {
        throw KoaRuntimeError.HandlerError(err)
      })

    return body !== undefined
      ? Response.json(body, { status })
      : new Response(undefined, { status })
  }
